	mmTryLock.TryLockMock.mutex.Lock()
	mmTryLock.TryLockMock.callArgs = append(mmTryLock.TryLockMock.callArgs, &mm_params)
	mmTryLock.TryLockMock.mutex.Unlock()

	for _, e := range mmTryLock.TryLockMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.err
		}
	}

	if mmTryLock.TryLockMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmTryLock.TryLockMock.defaultExpectation.Counter, 1)
		mm_want := mmTryLock.TryLockMock.defaultExpectation.params
		mm_want_ptrs := mmTryLock.TryLockMock.defaultExpectation.paramPtrs

		mm_got := LockerMockTryLockParams{ctx}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.ctx != nil && !minimock.Equal(*mm_want_ptrs.ctx, mm_got.ctx) {
				mmTryLock.t.Errorf("LockerMock.TryLock got unexpected parameter ctx, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmTryLock.TryLockMock.defaultExpectation.expectationOrigins.originCtx, *mm_want_ptrs.ctx, mm_got.ctx, minimock.Diff(*mm_want_ptrs.ctx, mm_got.ctx))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmTryLock.t.Errorf("LockerMock.TryLock got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmTryLock.TryLockMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmTryLock.TryLockMock.defaultExpectation.results
		if mm_results == nil {
			mmTryLock.t.Fatal("No results are set for the LockerMock.TryLock")
		}
		return (*mm_results).err
	}
	if mmTryLock.funcTryLock != nil {
		return mmTryLock.funcTryLock(ctx)
	}
	mmTryLock.t.Fatalf("Unexpected call to LockerMock.TryLock. %v", ctx)
