// MinimockTryLockDone returns true if the count of the TryLock invocations corresponds
// the number of defined expectations
func (m *LockerMock) MinimockTryLockDone() bool {
	if m.TryLockMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.TryLockMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.TryLockMock.invocationsDone()
}

// MinimockTryLockInspect logs each unmet expectation
func (m *LockerMock) MinimockTryLockInspect() {
	for _, e := range m.TryLockMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to LockerMock.TryLock at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterTryLockCounter := mm_atomic.LoadUint64(&m.afterTryLockCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.TryLockMock.defaultExpectation != nil && afterTryLockCounter < 1 {
		if m.TryLockMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to LockerMock.TryLock at\n%s", m.TryLockMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to LockerMock.TryLock at\n%s with params: %#v", m.TryLockMock.defaultExpectation.expectationOrigins.origin, *m.TryLockMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcTryLock != nil && afterTryLockCounter < 1 {
		m.t.Errorf("Expected call to LockerMock.TryLock at\n%s", m.funcTryLockOrigin)
	}

	if !m.TryLockMock.invocationsDone() && afterTryLockCounter > 0 {
		m.t.Errorf("Expected %d calls to LockerMock.TryLock at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.TryLockMock.expectedInvocations), m.TryLockMock.expectedInvocationsOrigin, afterTryLockCounter)
	}
}

