// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *LockerMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockKeyInspect()

			m.MinimockLockInspect()

			m.MinimockTryLockInspect()

			m.MinimockUnlockInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *LockerMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *LockerMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockKeyDone() &&
		m.MinimockLockDone() &&
		m.MinimockTryLockDone() &&
		m.MinimockUnlockDone()
}
